scwin.btn_onclick = function (e) {
  //f_Click() 통합

  scwin.g_selected_input_box = "ed_cntrNo";
  code = this.getValue();
  //scwin.f_twinkleBtn(code,80);
  // debugger;
  if (scwin.g_selected_input_box == "ed_cntrNo") {
    if (ed_cntrNo.getValue().length == 11) {
      //사번은 6자리
      return;
    }
    var value = ed_cntrNo.getValue();
    value = value + "" + code;
    ed_cntrNo.setValue(value);
  }
  ;
};
scwin.f_Check = function (e) {
  if (ed_cntrNo.getValue().length == 0) {
    scwin.g_selected_f_Check = "0";
    return;
  }
  ;
  scwin.g_selected_input_box = "ed_cntrNo";
};
scwin.f_DelClick = function () {
  //scwin.f_twinkleBtn("del");
  if (scwin.checkFixCntrNo == "1") {
    return false;
  }
  ;
  if (scwin.g_selected_input_box == 'ed_cntrNo') {
    var value = ed_cntrNo.getValue();
    if (value.length != 0) {
      value = value.substring(0, value.length - 1);
    }
    ed_cntrNo.setValue(value);
  }
  ;
};
scwin.btn_R_onclick = async function (e) {
  // r버튼
  await scwin.f_openCommonPopUp(1, ed_cntrNo, '', 'F', 'F');
};
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
  switch (disGubun) {
    case 1:
      if (ed_cntrNo.getValue().length >= 4) {
        pAllSearch = "T";
        pCode = ed_cntrNo.getValue();

        //alert(pCode.length);
        if (pCode.length == 11) {
          pCode = pCode.substr(pCode.length - 4, 4); //substr(pCode,(pCode.length)-4,4)
        } else if (pCode.length != 4) {
          $c.gus.cfAlertMsg($p, "컨테이너번호는 4자리로 입력하세요");
          ed_cntrNo.focus;
          return;
        }
        pName = "";
        pWhere = scwin.wrkPlCd;
        udc_comPop.setSelectId("retrieveCntrNoList");
        //alert(pCode+" " + pName+" " + pWhere);
        rtnList = await udc_comPop.cfCommonPopUp(scwin.callretrieveCntrNoList // XML상의 SELECT ID  
        , pCode // 화면에서의 ??? Code Element의  Value
        , pName // 화면에서의 ??? Name Element의  Value
        , 'T' // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
        , null // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
        , null // Title순서  
        , null // 보여주는 각 컬럼들의 폭    
        , "9,10" // 컬럼중에서 숨기는    컬럼 지정   
        , pWhere // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
        , null // POP-UP뛰을때 원도우의   사용자 정의  폭
        , null // POP-UP뛰을때 우도우의   사용자 정의  높이  
        , null // 윈도우 위치 Y좌표   
        , null // 윈도우 위치 X좌표
        , null // 중복체크여부   ("F")
        , pAllSearch // 전체검색허용여부 ("F")
        , "컨테이너" // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
        , "T");
        //alert("3");
      } else {
        $c.gus.cfAlertMsg($p, '컨테이너번호는 4자리로 입력하세요');
        ed_cntrNo.focus;
      }
      break;
  }
  if (!$c.gus.cfIsNull($p, ds_outInfo.getCellData(0, "alloccarNo")) && (ds_outInfo.getCellData(0, "reqClsCd") == "B" || ds_outInfo.getCellData(0, "reqClsCd") == "C")) {
    dma_CntrNoSeqInfo.set("cntrNo", ed_cntrNo.getValue());
    dma_CntrNoSeqInfo.set("ordrNo", ds_outInfo.getCellData(0, "odrNo"));
    dma_CntrNoSeqInfo.set("alloccarNo", ds_outInfo.getCellData(0, "alloccarNo"));
    dma_CntrNoSeqInfo.set("alloccarSeq", ds_outInfo.getCellData(0, "alloccarSeq"));
    dma_CntrNoSeqInfo.set("reqClsCd", ds_outInfo.getCellData(0, "reqClsCd"));
    dma_CntrNoSeqInfo.set("dptArvWrkPlCd", ds_outInfo.getCellData(0, "dptArvWrkPlCd"));
    $c.sbm.execute($p, smb_CntrNoSeqInfo);
  }
};
sbm_CntrNoSeqInfo_submitdone = function () {
  if (ds_CntrNoSeqInfo.getCellData(0, "cntrSeq") == 0 || cfIsNull(ds_CntrNoSeqInfo.getCellData(0, "cntrSeq"))) {
    ds_outInfo.setCellData(0, "cntrNo", "");
    $c.gus.cfAlertMsg($p, "조회결과가 존재하지 않습니다. 배차담당자에게 문의하세요!");
  }
};
scwin.callretrieveCntrNoList = async function (rtnList) {
  if (rtnList != null && rtnList[0] != "N/A") {
    ed_cntrNo.setValue(rtnList[0]);

    //광주CY full/empty구분값만 들어오는 경우 컨테이너 선택시 화면표시(라인, 사이즈 타입) 2015.09.14 hurrah
    if (scwin.wrkPlCd == "5C08") {
      ed_lineCd.setValue(rtnList[1]);
      ed_cntrSt.setValue(rtnList[2] + " " + rtnList[3]);
    }
    if (ed_cntrSt.getValue() != rtnList[2] + " " + rtnList[3] && scwin.wrkPlCd != "5C08") {
      $c.gus.cfAlertMsg($p, "사이즈 코드 또는  타입코드가 틀립니다. 컨테이너번호를 다시 조회해주십시오");
      ed_cntrNo.setValue(hid_cntr_no.getValue());
      ed_cntrNo.focus;
    } else if (ed_fullEmptyClsCd.getValue() != rtnList[4]) {
      //C2, C4인 경우에만 컨테이너 F/E구분 체크!!
      if (ed_odrKndCd.getValue() != 'C2' && ed_odrKndCd.getValue() != 'C4') {
        $c.gus.cfAlertMsg($p, "Full,Empty 구분코드가 틀립니다. 컨테이너번호를 다시 조회해주십시오");
        ed_cntrNo.setValue(hid_cntr_no.getValue());
        ed_cntrNo.focus;
      }
    } else if (rtnList[8] == 1) {
      $c.gus.cfAlertMsg($p, "SOC VAN으로 등록된컨테이너 입니다.");
      ed_cntrNo.setValue(hid_cntr_no.getValue());
      ed_cntrNo.focus;
    } else if (rtnList[9] == 'DMG') {
      $c.gus.cfAlertMsg($p, "데미지 컨테이너 입니다.");
      ed_cntrNo.setValue(hid_cntr_no.getValue());
      ed_cntrNo.focus;
    }
  } else {
    $c.gus.cfAlertMsg($p, "조회결과가 존재하지 않습니다. 배차담당자에게 문의하세요.");
    ed_cntrNo.setValue(hid_cntr_no.getValue());
  }
};
scwin.ed_cntrNo_ondblclick = function (e) {
  //f_resetText
  if (!$c.gus.cfIsNull($p, ed_cntrNo.getValue())) {
    ed_cntrNo.setValue("");
    ed_lineCd.setValue(scwin.orgLineCd);
    ed_cntrSt.setValue(scwin.orgCntrSt);
  }
};
scwin.btn_del_onclick = async function (e) {
  //del버튼
  if (scwin.onoffNo == null || scwin.onoffNo == "") {
    return;
  }
  ;
  let confirm = await $c.win.confirm($p, "작업을 삭제 하시겠습니까?");
  if (confirm) {
    ds_wrkInfo.set("onoffNo", scwin.onoffNo);
    scwin.tr_delete();
  }
  ;
};
scwin.sbm_retrieve_submitDone = function () {
  ed_odrKndCd.setValue(ds_outInfo.getCellData(0, "odrKndCd"));
  if ($c.gus.cfIsNull($p, scwin.orgLineCd)) scwin.orgLineCd = ds_outInfo.getCellData(0, "lineCd");
  if ($c.gus.cfIsNull($p, scwin.cntrSt)) scwin.orgCntrSt = ds_outInfo.getCellData(0, "cntrSt");
  ed_vehclNo.setValue(ds_outInfo.getCellData(0, "vehclNo"));
  ed_crryinoutClsCd.setValue(ds_outInfo.getCellData(0, "crryinoutClsCd"));
  ed_lineCd.setValue(ds_outInfo.getCellData(0, "lineCd"));
  ed_cntrSt.setValue(ds_outInfo.getCellData(0, "cntrSt"));
  ed_fullEmptyClsCd.setValue(ds_outInfo.getCellData(0, "fullEmptyClsCd"));
  ed_indcLblock.setValue(ds_outInfo.getCellData(0, "indcLblock"));
  ed_wrkMemo.setValue(ds_outInfo.getCellData(0, "wrkMemo"));
  if (ds_outInfo.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
  }
  ;
  if (ds_outInfo.getCellData(0, "cntrNo") != "" && ds_outInfo.getCellData(0, "cntrNo").length == 11) {
    //ed_cntrNo.setReadOnly(true);
    dma_hid_cmp.set("hid_cntr_no", ds_outInfo.getCellData(0, "cntrNo"));
    scwin.checkFixCntrNo = '1';
  }
  ;
  // if(ds_outInfo.getCellData(0, "crryinoutClsCd") == "O") {
  //     ed_crryinoutClsCd.setValue("상차");
  // } else {
  //     ed_crryinoutClsCd.setValue("하차");
  // }

  if (!$c.gus.cfIsNull($p, ds_outInfo.getCellData(0, "chgCntrNo"))) {
    tb_chgShow.show();
  } else {
    tb_chgShow.hide();
  }
};
scwin.crryinoutClsCdChange = function (e) {
  var rtv;
  if (ds_outInfo.getCellData(0, "crryinoutClsCd") == "O") {
    rtv = "상차";
  } else {
    rtv = "하차";
  }
  return rtv;
};
scwin.sbm_save_submitDone = function () {
  if (ds_outInfo.getCellData(0, "crryinoutClsCd") == "0") {
    ed_crryinoutClsCd.setValue("상차");
  } else {
    ed_crryinoutClsCd.setValue("하차");
  }
  ;
  scwin.f_back();
};
scwin.sbm_delete_submitDone = async function () {
  await $c.gus.cfAlertMsg($p, "작업이 삭제되었습니다. 작업 리스트로 돌아갑니다.");
  scwin.f_back();
};
